from functools import lru_cache

def min_leftover_chars(s: str, dictionary: list) -> int:
    """
    Finds the minimum number of leftover characters after splitting the string s into substrings,
    where each substring is a word from the dictionary and there are no overlaps.

    Parameters:
    s (str): The input string to be split.
    dictionary (list): A list of valid words from the dictionary.

    Returns:
    int: The minimum number of leftover characters.
    """

    @lru_cache(maxsize=None)
    def split_helper(start: int) -> int:
        if start == len(s):
            return 0

        min_leftovers = float('inf')

        for end in range(start + 1, len(s) + 1):
            if s[start:end] in dictionary:
                leftovers = split_helper(end)
                min_leftovers = min(min_leftovers, leftovers)

        return min_leftovers

    return split_helper(0)

