def shortest_after_removal(s):
    def remove_substring(s, substring):
        while substring in s:
            s = s.replace(substring, "")
        return len(s)

    # Calculate the length after removing "AB"
    length_remove_ab = remove_substring(s, "AB")

    # Calculate the length after removing "CD"
    length_remove_cd = remove_substring(s, "CD")

    # Return the minimum length between the two
    return min(length_remove_ab, length_remove_cd)

