def find_prime_pairs(n):
    def is_prime(num):
        if num <= 1:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    primes = [num for num in range(2, n) if is_prime(num)]
    prime_pairs = []

    for i in range(len(primes)):
        for j in range(i, len(primes)):
            if primes[i] + primes[j] == n:
                prime_pairs.append((primes[i], primes[j]))

    return prime_pairs

def find_prime_pairs(n):
    def sieve_of_eratosthenes(limit):
        """Generate all prime numbers up to limit using the Sieve of Eratosthenes."""
        sieve = [True] * (limit + 1)
        sieve[0] = sieve[1] = False
        for start in range(2, int(limit**0.5) + 1):
            if sieve[start]:
                for multiple in range(start*start, limit + 1, start):
                    sieve[multiple] = False
        return [num for num, is_prime in enumerate(sieve) if is_prime]

    primes = sieve_of_eratosthenes(n)
    prime_pairs = []

    for p1 in primes:
        p2 = n - p1
        if p2 >= p1 and p2 in primes:
            prime_pairs.append((p1, p2))

    return prime_pairs

